INSERT INTO t_p71061117_crm_client_managemen.help_sections (sort_order, icon, title, items) VALUES
(1, 'Users', 'Кандидаты', '[{"label":"Добавить кандидата","desc":"Нажмите кнопку «Добавить кандидата» в правом верхнем углу. Заполните форму: ФИО, телефон, город, гражданство, дату рождения и прочие данные. Прикрепите фото документов, билетов или контракта — файлы загружаются прямо из формы."},{"label":"Редактировать запись","desc":"Нажмите иконку карандаша (✏️) в строке кандидата. Откроется та же форма с уже заполненными данными — измените нужное и сохраните."},{"label":"Просмотр подробностей","desc":"Нажмите иконку глаза (👁) — откроется карточка кандидата со всей информацией и прикреплёнными файлами."},{"label":"Удалить кандидата","desc":"Кнопка удаления (🗑) доступна только администраторам. После нажатия запись удаляется без возможности восстановления."},{"label":"Отметить прозвон","desc":"В столбце «Прозвонен» есть чекбокс — нажмите его, чтобы отметить кандидата как прозвоненного (станет зелёным). Нажмите снова, чтобы снять отметку."}]'),
(2, 'Search', 'Поиск и фильтры', '[{"label":"Поиск по ФИО или сотруднику","desc":"Введите имя в строку поиска вверху страницы — таблица мгновенно фильтруется. Поиск работает по ФИО кандидата, имени сотрудника и возрасту."},{"label":"Фильтр «Непрозвоненные»","desc":"Кнопка «Непрозвоненные» в панели инструментов скрывает всех, кому уже позвонили. Удобно при ежедневном обзвоне — только те, кто ещё ждёт звонка."},{"label":"Обновить список","desc":"Кнопка с иконкой обновления (🔄) справа перезагружает данные из базы — полезно если коллеги одновременно работают в системе."}]'),
(3, 'FileDown', 'Выгрузка в Excel', '[{"label":"Скачать таблицу","desc":"Нажмите кнопку «Excel» в панели инструментов. В файл попадут только те записи, которые видны на экране — с учётом поиска и фильтров. Файл скачивается автоматически."}]'),
(4, 'Zap', 'Лиды с сайта', '[{"label":"Что такое лиды?","desc":"Лиды — это заявки от кандидатов, оставленные на внешнем сайте. Число новых лидов отображается оранжевым значком рядом с кнопкой «Лиды» в шапке."},{"label":"Обработка лидов","desc":"Перейдите в раздел «Лиды». Вы можете просмотреть заявку, отметить её как прозвоненную или удалить. Лиды также выгружаются в Excel."}]'),
(5, 'UserCog', 'Пользователи (только для администратора)', '[{"label":"Создать пользователя","desc":"В разделе «Пользователи» нажмите «Добавить пользователя». Укажите ФИО, логин, пароль и роль (Сотрудник или Администратор)."},{"label":"Сменить пароль пользователя","desc":"Администратор может сбросить пароль любого пользователя. Сотрудник может сменить только свой пароль — через своё имя в шапке страницы."},{"label":"Удалить пользователя","desc":"Нажмите иконку корзины рядом с пользователем. Удалённый пользователь потеряет доступ к системе немедленно."}]'),
(6, 'Phone', 'Телефония (Манго Офис)', '[{"label":"Как позвонить лиду","desc":"Перейдите в раздел «Лиды». В столбце «Телефон» нажмите на номер — он выделен синим цветом. Откроется приложение Манго Офис, которое автоматически наберёт номер."},{"label":"Установка Манго Офис на компьютер","desc":"Скачайте приложение Манго Офис с официального сайта mango-office.ru. После установки войдите в приложение под своими рабочими учётными данными."},{"label":"Фиксация результата звонка","desc":"После звонка лиду нажмите кнопку «Выбрать» в столбце «Результат» напротив нужного лида. Выберите один из вариантов: Недозвон, Занято, Отказ, Заинтересован, Перезвонит или Дубль."},{"label":"Фильтр «Непрозвоненные»","desc":"Кнопка «Непрозвоненные» вверху страницы Лидов показывает только те заявки, по которым ещё не был выбран результат звонка."},{"label":"Входящий звонок автоматически создаёт лида","desc":"Если клиент сам звонит на рабочий номер компании, система Манго передаёт этот звонок в CRM и автоматически создаёт нового лида с номером телефона."}]'),
(7, 'Smartphone', 'Установка приложения на телефон', '[{"label":"iPhone (Safari)","desc":"1. Откройте сайт в браузере Safari. 2. Нажмите кнопку «Поделиться» (квадрат со стрелкой вверх) внизу экрана. 3. Выберите «На экран «Домой»». 4. Нажмите «Добавить»."},{"label":"Android — Chrome","desc":"1. Откройте сайт в браузере Chrome. 2. Нажмите «⋮» (три точки) в правом верхнем углу. 3. Выберите «Добавить на главный экран». 4. Нажмите «Добавить»."},{"label":"Android — Яндекс Браузер","desc":"1. Откройте сайт в Яндекс Браузере. 2. Нажмите «⋮» (три точки) внизу экрана. 3. Выберите «Добавить на рабочий стол». 4. Нажмите «Добавить»."}]'),
(8, 'User', 'Личный кабинет', '[{"label":"Сменить пароль","desc":"Нажмите на своё имя в правом верхнем углу — откроется форма смены пароля. Введите текущий и новый пароль."},{"label":"Выйти из системы","desc":"Нажмите иконку выхода (стрелка вправо) рядом со своим именем. Сессия будет завершена."}]');
